class Data {
  Data({
    this.viewType,
    this.pageInfo,
    this.tabs,
    this.currentFilter,
    this.events,
    this.bookings,
    this.pagination,});

  Data.fromJson(dynamic json) {
    viewType = json['viewType'];
    pageInfo = json['pageInfo'] != null ? PageInfo.fromJson(json['pageInfo']) : null;
    if (json['tabs'] != null) {
      tabs = [];
      json['tabs'].forEach((v) {
        tabs?.add(Tabs.fromJson(v));
      });
    }
    currentFilter = json['currentFilter'];
    if (json['events'] != null) {
      events = [];
      json['events'].forEach((v) {
        events?.add(Events.fromJson(v));
      });
    }
    if (json['bookings'] != null) {
      bookings = [];
      json['bookings'].forEach((v) {
        bookings?.add(RenterBookings.fromJson(v));
      });
    }
    pagination = json['pagination'] != null ? Pagination.fromJson(json['pagination']) : null;
  }
  String? viewType;
  PageInfo? pageInfo;
  List<Tabs>? tabs;
  String? currentFilter;
  List<Events>? events;
  List<RenterBookings>? bookings;
  Pagination? pagination;
  Data copyWith({  String? viewType,
    PageInfo? pageInfo,
    List<Tabs>? tabs,
    String? currentFilter,
    List<Events>? events,
    List<RenterBookings>? bookings,
    Pagination? pagination,
  }) => Data(  viewType: viewType ?? this.viewType,
    pageInfo: pageInfo ?? this.pageInfo,
    tabs: tabs ?? this.tabs,
    currentFilter: currentFilter ?? this.currentFilter,
    events: events ?? this.events,
    bookings: bookings ?? this.bookings,
    pagination: pagination ?? this.pagination,
  );
  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['viewType'] = viewType;
    if (pageInfo != null) {
      map['pageInfo'] = pageInfo?.toJson();
    }
    if (tabs != null) {
      map['tabs'] = tabs?.map((v) => v.toJson()).toList();
    }
    map['currentFilter'] = currentFilter;
    if (events != null) {
      map['events'] = events?.map((v) => v.toJson()).toList();
    }
    if (bookings != null) {
      map['bookings'] = bookings?.map((v) => v.toJson()).toList();
    }
    if (pagination != null) {
      map['pagination'] = pagination?.toJson();
    }
    return map;
  }

}

