/// fullAddress : "wsredfgadsf, Abou Simbel, Aswan"
/// city : "Abou Simbel"
/// street : "wsredfgadsf"

class Location {
  Location({
    this.fullAddress,
    this.city,
    this.street,});

  // Location.fromJson(dynamic json) {
  //   fullAddress = json['fullAddress'];
  //   city = json['city'];
  //   street = json['street'];
  // }
  Location.fromJson(dynamic json) {
    // 1. If unfiltered, json is a Map: {"fullAddress": "...", "city": "..."}
    if (json is Map<String, dynamic>) {
      fullAddress = json['fullAddress'];
      city = json['city'];
      street = json['street'];
    }

    // 2. If filtered, json is a raw String: "شارع النيل, Amiriyyah"
    else if (json is String) {
      // We catch the string here, assign it to fullAddress, and prevent the crash!
      fullAddress = json;

      // Optional: We parse the string to populate the other fields manually
      final parts = json.split(',');
      if (parts.length >= 2) {
        street = parts[0].trim();
        city = parts[1].trim();
      } else {
        street = json;
      }
    }
  }
  String? fullAddress;
  String? city;
  String? street;
  Location copyWith({  String? fullAddress,
    String? city,
    String? street,
  }) => Location(  fullAddress: fullAddress ?? this.fullAddress,
    city: city ?? this.city,
    street: street ?? this.street,
  );
  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['fullAddress'] = fullAddress;
    map['city'] = city;
    map['street'] = street;
    return map;
  }

}

